const html = "<!DOCTYPE html>
<html lang="pt-BR" data-bs-theme="dark" style="background-color: #060b14;">

<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>ibusiness Prospector - Prospecção Inteligente por IA</title>

    <!-- Bootstrap CSS -->
    <link href="https://cdn.jsdelivr.net/npm/bootstrap@5.3.2/dist/css/bootstrap.min.css" rel="stylesheet">
    <!-- Bootstrap Icons -->
    <link rel="stylesheet" href="https://cdn.jsdelivr.net/npm/bootstrap-icons@1.11.1/font/bootstrap-icons.css">
    <!-- Leaflet CSS -->
    <link rel="stylesheet" href="https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/leaflet.css" />
    <!-- Leaflet JS -->
    <script src="https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/leaflet.min.js"></script>

    <style>
        @import url('https://fonts.googleapis.com/css2?family=Plus+Jakarta+Sans:wght@300;400;500;600;700;800&display=swap');

        :root {
            --bg-deep: #060b14;
            --bg-base: #0a1122;
            --bg-raised: #0f1a2e;
            --bg-surface: #132038;
            --cyan: #00D4FF;
            --cyan-dim: #0099cc;
            --cyan-glow: rgba(0, 212, 255, 0.12);
            --cyan-border: rgba(0, 212, 255, 0.2);
            --green: #25D366;
            --green-glow: rgba(37, 211, 102, 0.12);
            --green-border: rgba(37, 211, 102, 0.25);
            --red: #E53935;
            --red-glow: rgba(229, 57, 53, 0.12);
            --amber: #FFB300;
            --text-primary: #e8edf5;
            --text-secondary: #8899b4;
            --text-muted: #556b8a;
            --border: rgba(255, 255, 255, 0.06);
            --border-hover: rgba(255, 255, 255, 0.12);
            --radius-sm: 8px;
            --radius-md: 12px;
            --radius-lg: 16px;
            --radius-xl: 20px;
            --shadow-sm: 0 2px 8px rgba(0,0,0,0.3);
            --shadow-md: 0 4px 24px rgba(0,0,0,0.4);
            --shadow-lg: 0 8px 40px rgba(0,0,0,0.5);
            --font: 'Plus Jakarta Sans', -apple-system, BlinkMacSystemFont, sans-serif;
            --transition: 0.2s cubic-bezier(0.4, 0, 0.2, 1);
        }

        * { box-sizing: border-box; }

        html, body {
            font-family: var(--font) !important;
            background: var(--bg-deep) !important;
            color: var(--text-primary) !important;
            -webkit-font-smoothing: antialiased;
            -moz-osx-font-smoothing: grayscale;
        }

        /* ===== SCROLLBAR ===== */
        ::-webkit-scrollbar { width: 6px; }
        ::-webkit-scrollbar-track { background: var(--bg-deep); }
        ::-webkit-scrollbar-thumb { background: var(--bg-surface); border-radius: 3px; }
        ::-webkit-scrollbar-thumb:hover { background: var(--text-muted); }

        /* ===== NAVBAR ===== */
        .navbar {
            background: var(--bg-base) !important;
            border-bottom: 1px solid var(--border) !important;
            backdrop-filter: blur(20px);
            padding: 0.6rem 1.5rem !important;
            box-shadow: none !important;
        }
        .navbar-brand { font-weight: 700 !important; }
        .navbar .btn-outline-secondary {
            border-color: var(--border) !important;
            color: var(--text-secondary) !important;
            border-radius: var(--radius-sm) !important;
            padding: 6px 10px !important;
            transition: var(--transition);
        }
        .navbar .btn-outline-secondary:hover {
            background: var(--cyan-glow) !important;
            border-color: var(--cyan-border) !important;
            color: var(--cyan) !important;
        }
        .navbar .btn-outline-danger {
            border-color: var(--border) !important;
            color: var(--text-muted) !important;
            border-radius: var(--radius-sm) !important;
            padding: 6px 10px !important;
        }
        .navbar .btn-outline-danger:hover {
            background: var(--red-glow) !important;
            border-color: var(--red) !important;
            color: var(--red) !important;
        }

        /* ===== GRADIENT TEXT ===== */
        .gradient-text {
            background: linear-gradient(135deg, var(--cyan), #00e5ff) !important;
            -webkit-background-clip: text !important;
            -webkit-text-fill-color: transparent !important;
            background-clip: text !important;
            font-size: 1.4rem !important;
        }

        /* ===== GRADIENT BUTTONS ===== */
        .gradient-bg {
            background: linear-gradient(135deg, var(--cyan), var(--cyan-dim)) !important;
            border: none !important;
            border-radius: var(--radius-md) !important;
            font-weight: 600 !important;
            letter-spacing: 0.02em;
            transition: var(--transition);
            box-shadow: 0 2px 12px rgba(0, 212, 255, 0.25);
        }
        .gradient-bg:hover {
            box-shadow: 0 4px 20px rgba(0, 212, 255, 0.4) !important;
            transform: translateY(-1px);
        }
        .gradient-bg-success {
            background: linear-gradient(135deg, var(--green), var(--cyan)) !important;
        }

        /* ===== HERO SECTION ===== */
        .hero-section {
            background: linear-gradient(135deg, rgba(0,212,255,0.08), rgba(0,153,204,0.04)) !important;
            border: 1px solid var(--cyan-border) !important;
            border-radius: var(--radius-xl) !important;
            color: var(--text-primary) !important;
            padding: 2rem !important;
            margin-bottom: 1.5rem !important;
        }
        .hero-section h1 {
            font-size: 1.6rem !important;
            font-weight: 700 !important;
            color: var(--text-primary) !important;
        }
        .hero-section h1 i { color: var(--cyan); }
        .hero-section .lead {
            color: var(--text-secondary) !important;
            font-size: 0.95rem !important;
            font-weight: 400;
        }

        /* ===== CARDS ===== */
        .card {
            background: var(--bg-base) !important;
            border: 1px solid var(--border) !important;
            border-radius: var(--radius-lg) !important;
            box-shadow: none !important;
        }
        .card-header {
            background: transparent !important;
            border-bottom: 1px solid var(--border) !important;
            padding: 1rem 1.25rem !important;
        }
        .card-title { color: var(--text-primary) !important; font-weight: 600 !important; }
        .card-body { padding: 1.25rem !important; }

        /* ===== SEARCH HEADER ===== */
        .search-header {
            background: transparent !important;
            border-radius: 0 !important;
        }

        /* ===== PROSPECT CARDS ===== */
        .prospect-card {
            background: var(--bg-raised) !important;
            border: 1px solid var(--border) !important;
            border-radius: var(--radius-md) !important;
            transition: var(--transition) !important;
            cursor: pointer;
        }
        .prospect-card:hover {
            border-color: var(--cyan-border) !important;
            box-shadow: 0 0 0 1px var(--cyan-border), var(--shadow-sm) !important;
            transform: translateY(-1px) !important;
        }
        .prospect-card.selected {
            border: 1px solid var(--cyan) !important;
            background: rgba(0, 212, 255, 0.06) !important;
            box-shadow: 0 0 0 1px var(--cyan), 0 0 20px rgba(0,212,255,0.1) !important;
        }

        /* ===== STATS CARDS ===== */
        .stats-card {
            background: var(--bg-raised) !important;
            border: 1px solid var(--border) !important;
            border-radius: var(--radius-md) !important;
            transition: var(--transition) !important;
        }
        .stats-card:hover {
            border-color: var(--border-hover) !important;
            transform: translateY(-1px) !important;
        }
        .stats-card .fs-2 { font-weight: 700 !important; font-size: 1.75rem !important; }

        /* ===== FORM CONTROLS ===== */
        .form-control, .form-select {
            background: var(--bg-raised) !important;
            border: 1px solid var(--border) !important;
            color: var(--text-primary) !important;
            border-radius: var(--radius-sm) !important;
            transition: var(--transition);
        }
        .form-control:focus, .form-select:focus {
            border-color: var(--cyan) !important;
            box-shadow: 0 0 0 2px rgba(0,212,255,0.15) !important;
            background: var(--bg-surface) !important;
        }
        .form-control::placeholder { color: var(--text-muted) !important; }
        .input-group-text {
            background: var(--bg-surface) !important;
            border: 1px solid var(--border) !important;
            color: var(--text-muted) !important;
            border-radius: var(--radius-sm) 0 0 var(--radius-sm) !important;
        }
        .form-label { color: var(--text-secondary) !important; font-weight: 500 !important; font-size: 0.85rem !important; }
        .form-text { color: var(--text-muted) !important; }

        /* ===== BUTTONS ===== */
        .btn { border-radius: var(--radius-sm) !important; font-weight: 500 !important; transition: var(--transition); }
        .btn-primary {
            background: var(--cyan) !important;
            border-color: var(--cyan) !important;
            color: var(--bg-deep) !important;
            font-weight: 600 !important;
        }
        .btn-primary:hover { background: #00e5ff !important; box-shadow: 0 2px 12px rgba(0,212,255,0.3) !important; }
        .btn-outline-primary {
            border-color: var(--cyan-border) !important;
            color: var(--cyan) !important;
        }
        .btn-outline-primary:hover {
            background: var(--cyan-glow) !important;
            border-color: var(--cyan) !important;
        }
        .btn-outline-secondary {
            border-color: var(--border) !important;
            color: var(--text-secondary) !important;
        }
        .btn-outline-secondary:hover {
            background: var(--bg-surface) !important;
            border-color: var(--border-hover) !important;
            color: var(--text-primary) !important;
        }
        .btn-success { background: var(--green) !important; border-color: var(--green) !important; color: #fff !important; }
        .btn-outline-success { border-color: var(--green-border) !important; color: var(--green) !important; }
        .btn-outline-success:hover { background: var(--green-glow) !important; }
        .btn-outline-danger { border-color: rgba(229,57,53,0.25) !important; color: var(--red) !important; }
        .btn-outline-danger:hover { background: var(--red-glow) !important; }
        .btn-outline-info { border-color: var(--cyan-border) !important; color: var(--cyan) !important; }
        .btn-outline-info:hover { background: var(--cyan-glow) !important; }
        .btn-warning { background: var(--amber) !important; border-color: var(--amber) !important; color: var(--bg-deep) !important; }
        .btn-danger { background: var(--red) !important; border-color: var(--red) !important; }
        .btn-secondary { background: var(--bg-surface) !important; border-color: var(--border) !important; color: var(--text-secondary) !important; }

        /* ===== BADGES ===== */
        .badge { font-weight: 500 !important; letter-spacing: 0.02em; border-radius: 6px !important; }
        .badge.bg-primary { background: var(--cyan) !important; color: var(--bg-deep) !important; }
        .badge.bg-success { background: var(--green) !important; }
        .badge.bg-danger { background: var(--red) !important; }
        .badge.bg-secondary { background: var(--bg-surface) !important; color: var(--text-secondary) !important; }
        .badge.bg-light { background: var(--bg-raised) !important; color: var(--text-primary) !important; }
        .badge.bg-warning { background: var(--amber) !important; color: var(--bg-deep) !important; }
        .badge.bg-info { background: var(--cyan-glow) !important; color: var(--cyan) !important; }

        /* ===== WHATSAPP STATUS ===== */
        .whatsapp-status {
            font-size: 0.65rem !important;
            padding: 2px 8px !important;
            border-radius: 20px !important;
            font-weight: 600 !important;
            letter-spacing: 0.03em;
            text-transform: uppercase;
        }

        /* ===== RATING ===== */
        .rating-stars { color: var(--amber) !important; font-size: 0.8rem; }

        /* ===== WEBHOOK SECTION ===== */
        .webhook-section {
            background: var(--bg-raised) !important;
            border: 1px solid var(--green-border) !important;
            border-radius: var(--radius-lg) !important;
            border-style: solid !important;
        }
        .webhook-section h5 { font-size: 1rem !important; font-weight: 600 !important; }

        /* ===== WEBHOOK STATUS ===== */
        .webhook-status { padding: 10px; border-radius: var(--radius-sm); margin-top: 10px; font-size: 0.85rem; }
        .webhook-success { background: var(--green-glow); border: 1px solid var(--green-border); color: var(--green); }
        .webhook-error { background: var(--red-glow); border: 1px solid rgba(229,57,53,0.25); color: var(--red); }
        .webhook-loading { background: var(--cyan-glow); border: 1px solid var(--cyan-border); color: var(--cyan); }

        /* ===== MAP ===== */
        #minimap {
            height: 280px !important;
            border-radius: var(--radius-md) !important;
            border: 1px solid var(--border) !important;
        }

        /* ===== PAGINATION ===== */
        .pagination-controls {
            background: var(--bg-raised) !important;
            border: 1px solid var(--border) !important;
            border-radius: var(--radius-md) !important;
            padding: 12px 16px !important;
            margin: 16px 0 !important;
        }

        /* ===== FILTER STATUS ===== */
        .filter-status {
            background: var(--cyan-glow) !important;
            border: 1px solid var(--cyan-border) !important;
            border-radius: var(--radius-sm) !important;
            padding: 8px 12px;
            font-size: 0.8rem;
            margin-bottom: 12px;
        }

        /* ===== LOADING ===== */
        .loading-spinner { display: none; }

        /* ===== ANIMATIONS ===== */
        .fade-in {
            animation: fadeUp 0.3s cubic-bezier(0.4, 0, 0.2, 1) both;
        }
        @keyframes fadeUp {
            from { opacity: 0; transform: translateY(8px); }
            to { opacity: 1; transform: translateY(0); }
        }

        /* ===== MODALS ===== */
        .modal-content {
            background: var(--bg-base) !important;
            border: 1px solid var(--border) !important;
            border-radius: var(--radius-lg) !important;
            box-shadow: var(--shadow-lg) !important;
        }
        .modal-header {
            border-bottom: 1px solid var(--border) !important;
            padding: 1.25rem !important;
        }
        .modal-footer {
            border-top: 1px solid var(--border) !important;
            padding: 1rem 1.25rem !important;
        }
        .modal-title { font-weight: 600 !important; }
        .modal-backdrop { backdrop-filter: blur(4px); }

        /* ===== ALERTS ===== */
        .alert-info {
            background: var(--cyan-glow) !important;
            border: 1px solid var(--cyan-border) !important;
            color: var(--cyan) !important;
            border-radius: var(--radius-sm) !important;
        }
        .alert-warning {
            background: rgba(255,179,0,0.1) !important;
            border: 1px solid rgba(255,179,0,0.25) !important;
            color: var(--amber) !important;
        }
        .alert-danger {
            background: var(--red-glow) !important;
            border: 1px solid rgba(229,57,53,0.25) !important;
            color: var(--red) !important;
        }

        /* ===== TOASTS ===== */
        .toast {
            background: var(--bg-surface) !important;
            border: 1px solid var(--border) !important;
            border-radius: var(--radius-md) !important;
            box-shadow: var(--shadow-md) !important;
        }
        .toast-header {
            background: transparent !important;
            border-bottom: 1px solid var(--border) !important;
            color: var(--text-primary) !important;
        }
        .toast-body { color: var(--text-secondary) !important; }

        /* ===== TEXT UTILITIES ===== */
        .text-muted { color: var(--text-muted) !important; }
        .text-success { color: var(--green) !important; }
        .text-danger { color: var(--red) !important; }
        .text-warning { color: var(--amber) !important; }
        .text-info { color: var(--cyan) !important; }
        .text-primary { color: var(--cyan) !important; }
        .text-white { color: var(--text-primary) !important; }
        a { color: var(--cyan); }
        a:hover { color: #00e5ff; }

        /* ===== BG UTILITIES ===== */
        .bg-body-tertiary { background: var(--bg-base) !important; }
        .bg-dark { background: var(--bg-raised) !important; }
        .bg-warning { background: rgba(255,179,0,0.15) !important; }
        .border-secondary { border-color: var(--border) !important; }

        /* ===== FORM CHECK ===== */
        .form-check-input {
            background-color: var(--bg-surface) !important;
            border-color: var(--border) !important;
        }
        .form-check-input:checked {
            background-color: var(--cyan) !important;
            border-color: var(--cyan) !important;
        }

        /* ===== CLOSE BUTTON ===== */
        .btn-close { filter: invert(1) grayscale(100%) brightness(200%); }

        /* ===== LOGIN SCREEN ===== */
        #login-screen {
            background: radial-gradient(ellipse 80% 60% at 50% 0%, rgba(0,212,255,0.06), transparent),
                        var(--bg-deep) !important;
        }
        #login-screen .card {
            background: var(--bg-base) !important;
            border: 1px solid var(--border) !important;
            box-shadow: var(--shadow-lg), 0 0 80px rgba(0,212,255,0.05) !important;
        }

        /* ===== LEAFLET OVERRIDES ===== */
        .leaflet-popup-content-wrapper {
            background: var(--bg-surface) !important;
            color: var(--text-primary) !important;
            border-radius: var(--radius-md) !important;
            box-shadow: var(--shadow-md) !important;
        }
        .leaflet-popup-tip { background: var(--bg-surface) !important; }
        .prospect-popup { min-width: 200px; }
        .prospect-popup h6 { margin: 0 0 5px 0; color: var(--cyan) !important; }
        .prospect-popup .badge { font-size: 0.65rem; }

        /* ===== SELECTION GLOW ===== */
        ::selection { background: rgba(0, 212, 255, 0.3); color: #fff; }

        /* ===== RESPONSIVE ===== */
        @media (max-width: 768px) {
            .hero-section h1 { font-size: 1.2rem !important; }
            .gradient-text { font-size: 1.1rem !important; }
        }

    </style>
</head>

<body>
    <!-- Login Screen -->
    <div id="login-screen" class="d-flex align-items-center justify-content-center" style="min-height:100vh;background:#060b14;">
        <div class="card shadow-lg" style="max-width:420px;width:100%;background:#0a1122;border:1px solid rgba(255,255,255,.06);">
            <div class="card-body p-4">
                <div class="text-center mb-4">
                    <img src="data:image/png;base64," alt="ibusiness" style="height:40px;" class="mb-3">
