            }

            const hasUazapi = WHATSAPP_API_CONFIG.baseUrl && WHATSAPP_API_CONFIG.token;

            if (!hasUazapi) {
                debugLog('⚠️ Uazapi não configurada - WhatsApp será marcado como "não verificado"');
            }

            const searchTerm = searchInput.value.trim();

            if (!searchTerm) {
