            const avgRatingEl = document.getElementById('avg-rating');

            if (selectedCountEl) selectedCountEl.textContent = selectedProspects.size;

            if (resultsCountEl) {
                const pageText = currentPage > 1 ? ` (Página ${currentPage})` : '';
