        // Send data to webhook with random intervals and pause/stop controls
        async function sendDataToWebhook(prospects, type) {
            const webhookBtn = document.getElementById('webhook-btn');
            const webhookAllBtn = document.getElementById('webhook-all-btn');
            const pauseBtnContainer = document.getElementById('pause-btn-container');
            const stopBtnContainer = document.getElementById('stop-btn-container');
            const pauseBtn = document.getElementById('pause-btn');
            const statusContainer = document.getElementById('webhook-status-container');

            // Get interval settings (default: 30-60 seconds)
            const minInterval = parseInt(safeStorage.getItem('webhook_min_interval') || '30');
            const maxInterval = parseInt(safeStorage.getItem('webhook_max_interval') || '60');

            // Initialize sending state
            webhookSendingState = {
                isRunning: true,
                isPaused: false,
                isStopped: false,
                currentIndex: 0,
                totalProspects: prospects.length
            };

            // Show control buttons
            pauseBtnContainer.classList.remove('d-none');
            stopBtnContainer.classList.remove('d-none');

            // Show loading status
            showWebhookStatus('loading', `Iniciando envio de ${prospects.length} prospects...`);

            // Disable main buttons during sending
            if (webhookBtn) webhookBtn.disabled = true;
            if (webhookAllBtn) webhookAllBtn.disabled = true;

            let successCount = 0;
            let errorCount = 0;

            try {
                debugLog(`Enviando ${prospects.length} prospects para webhook com controles`);

                for (let i = 0; i < prospects.length; i++) {
                    // Check if stopped
                    if (webhookSendingState.isStopped) {
                        showWebhookStatus('error', `❌ Envio interrompido pelo usuário. ${successCount} enviados, ${errorCount} erros.`);
                        break;
                    }

                    // Handle pause
                    while (webhookSendingState.isPaused && !webhookSendingState.isStopped) {
                        showWebhookStatus('loading', `⏸️ Pausado na empresa ${i + 1}/${prospects.length}. (${successCount} enviados, ${errorCount} erros)`);
                        await new Promise(resolve => setTimeout(resolve, 1000));
                    }

                    // Check if stopped after pause
                    if (webhookSendingState.isStopped) {
                        showWebhookStatus('error', `❌ Envio interrompido pelo usuário. ${successCount} enviados, ${errorCount} erros.`);
                        break;
                    }

                    const prospect = prospects[i];
                    webhookSendingState.currentIndex = i;

                    // Clean and format phone number
                    let cleanPhone = '';
                    if (prospect.telefone && prospect.telefone !== 'Telefone não disponível') {
                        cleanPhone = prospect.telefone.replace(/\D/g, '');

                        if (cleanPhone.length >= 10 && !cleanPhone.startsWith('55')) {
                            cleanPhone = '55' + cleanPhone;
                        }
                    }

                    // Prepare individual prospect data
                    const webhookData = {
                        nome_empresa: prospect.name,
                        telefone: cleanPhone || 'Não informado',
                        telefone_original: prospect.telefone || 'Não informado',
                        rating_google: prospect.rating || 0,
                        reviews_google: prospect.reviews || 0,
                        especialidades: prospect.types || 'Não informado',
                        site_empresa: prospect.website || 'Não informado',
                        has_whatsapp: prospect.hasWhatsApp === true ? 'Sim' : prospect.hasWhatsApp === false ? 'Não' : 'Não verificado'
                    };

                    // Update status
                    showWebhookStatus('loading',
                        `Enviando ${i + 1}/${prospects.length}: ${prospect.name}... (${successCount} enviados, ${errorCount} erros)`
                    );

                    try {
                        // Send individual prospect to webhook
                        const response = await fetch(WEBHOOK_CONFIG.url, {
                            method: 'POST',
                            headers: {
                                'Content-Type': 'application/json',
                            },
                            body: JSON.stringify({
                                prospect: webhookData,
                                prospect_number: i + 1,
                                total_prospects: prospects.length,
                                timestamp: new Date().toISOString(),
                                source: 'ibusiness Prospector',
                                business_profile: BUSINESS_PROFILE_CONFIG,
                    openai_api_key: safeStorage.getItem('openai_api_key') || '',
                    tenant_id: currentTenant ? currentTenant.id : '',
                                openai_api_key: safeStorage.getItem('openai_api_key') || '',
                                tenant_id: currentTenant ? currentTenant.id : '',
                                uazapi_config: getSelectedInstanceConfig()
                            })
                        });

                        if (response.ok) {
                            successCount++;
                            debugLog(`Prospect ${i + 1} enviado com sucesso: ${prospect.name} - Tel: ${cleanPhone}`);
                        } else {
                            errorCount++;
                            const errorText = await response.text();
                            debugLog(`Erro ao enviar prospect ${i + 1}:`, { status: response.status, error: errorText });
                        }

                    } catch (error) {
                        errorCount++;
                        debugLog(`Erro de conexão no prospect ${i + 1}:`, error);
                    }

                    // Wait random interval before next send (except for the last one)
                    if (i < prospects.length - 1 && !webhookSendingState.isStopped) {
                        const randomInterval = Math.floor(Math.random() * (maxInterval - minInterval + 1)) + minInterval;
                        debugLog(`Aguardando ${randomInterval}s antes do próximo envio...`);

                        // Show countdown with pause/stop checks
                        for (let countdown = randomInterval; countdown > 0; countdown--) {
                            // Check if stopped during countdown
                            if (webhookSendingState.isStopped) {
                                break;
                            }

                            // Handle pause during countdown
                            while (webhookSendingState.isPaused && !webhookSendingState.isStopped) {
                                showWebhookStatus('loading', `⏸️ Pausado. Próximo em ${countdown}s quando retomar...`);
                                await new Promise(resolve => setTimeout(resolve, 1000));
                            }

                            // Check if stopped after pause
                            if (webhookSendingState.isStopped) {
                                break;
                            }

                            showWebhookStatus('loading',
                                `Próximo envio em ${countdown}s... (${successCount} enviados, ${errorCount} erros)`
                            );
                            await new Promise(resolve => setTimeout(resolve, 1000));
                        }
                    }
                }

                // Final status (only if not stopped)
                if (!webhookSendingState.isStopped) {
                    if (errorCount === 0) {
                        showWebhookStatus('success', `✅ Todos os ${successCount} prospects enviados com sucesso!`);
                        showSuccessToast(`🚀 Envio concluído! ${successCount} prospects processados pela IA.`);
                    } else {
                        showWebhookStatus('success', `⚠️ Envio concluído: ${successCount} sucessos, ${errorCount} erros`);
                        showSuccessToast(`📊 Envio concluído: ${successCount} enviados, ${errorCount} com erro.`);
                    }
                }

                debugLog('Envio em lote concluído:', {
                    total: prospects.length,
                    sucessos: successCount,
                    erros: errorCount,
                    interrompido: webhookSendingState.isStopped,
                    type: type,
                    webhook_url: WEBHOOK_CONFIG.url
                });

            } catch (error) {
                console.error('Erro geral no envio:', error);
                debugLog('Erro geral no webhook:', error);

                showWebhookStatus('error', `❌ Erro geral: ${error.message}`);
                showErrorToast(`❌ Falha no envio: ${error.message}`);
            } finally {
                // Reset sending state
                webhookSendingState.isRunning = false;

                // Hide control buttons
                pauseBtnContainer.classList.add('d-none');
                stopBtnContainer.classList.add('d-none');

                // Re-enable buttons
                updateWebhookButtons();
            }
        }

        // Pause webhook sending
        function pauseWebhookSending() {
            const pauseBtn = document.getElementById('pause-btn');

            if (webhookSendingState.isPaused) {
                // Resume
                webhookSendingState.isPaused = false;
                pauseBtn.innerHTML = '<i class="bi bi-pause-circle me-2"></i>Pausar';
                pauseBtn.className = 'btn btn-warning w-100';
                showSuccessToast('▶️ Envio retomado!');
                debugLog('Envio retomado pelo usuário');
            } else {
                // Pause
                webhookSendingState.isPaused = true;
                pauseBtn.innerHTML = '<i class="bi bi-play-circle me-2"></i>Retomar';
                pauseBtn.className = 'btn btn-success w-100';
                showSuccessToast('⏸️ Envio pausado!');
                debugLog('Envio pausado pelo usuário');
            }
        }

        // Stop webhook sending
        function stopWebhookSending() {
            const confirmStop = confirm('⚠️ Tem certeza que deseja parar o envio?\n\nEsta ação não pode ser desfeita.');

            if (confirmStop) {
                webhookSendingState.isStopped = true;
                webhookSendingState.isPaused = false;

                showErrorToast('🛑 Envio interrompido pelo usuário!');
                debugLog('Envio interrompido pelo usuário');

                // Update status immediately
                const successCount = webhookSendingState.currentIndex || 0;
                const errorCount = webhookSendingState.totalProspects - successCount;
                showWebhookStatus('error', `🛑 Envio interrompido! ${successCount} prospects foram enviados.`);
            }
        }

        // Show webhook status
        function showWebhookStatus(type, message) {
            const statusContainer = document.getElementById('webhook-status-container');
            if (!statusContainer) return;

            let statusClass = '';
            let icon = '';

            switch (type) {
                case 'loading':
                    statusClass = 'webhook-loading';
                    icon = '<i class="bi bi-hourglass-split me-2"></i>';
                    break;
                case 'success':
                    statusClass = 'webhook-success';
                    icon = '<i class="bi bi-check-circle-fill me-2"></i>';
                    break;
                case 'error':
                    statusClass = 'webhook-error';
                    icon = '<i class="bi bi-exclamation-triangle-fill me-2"></i>';
                    break;
            }

            statusContainer.innerHTML = `
                <div class="webhook-status ${statusClass}">
                    ${icon}${message}
                </div>
            `;

            // Auto-hide success/error messages after 5 seconds
            if (type !== 'loading') {
                setTimeout(() => {
                    statusContainer.innerHTML = '';
                }, 5000);
            }
        }

