        // ============================================================
        // GERENCIAMENTO DE INSTÂNCIAS WHATSAPP (Uazapi)
        // ============================================================
        const MAX_INSTANCES = 3;
        var whatsappInstances = [];

        async function loadInstances() {
            // Cache from safeStorage first (instant UI)
            const saved = safeStorage.getItem('whatsapp_instances');
            if (saved) {
                try { whatsappInstances = JSON.parse(saved); } catch(e) { whatsappInstances = []; }
            }
            renderInstances();

            // Then refresh from server (source of truth)
            if (!currentTenant || !currentTenant.id) return;
            try {
                const resp = await fetch(getAuthWebhookBase() || '', {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({ action: 'list_instances', tenant_id: currentTenant.id })
                });
                const data = await resp.json();
                if (data && data.success && Array.isArray(data.instances)) {
                    whatsappInstances = data.instances.map(function(i) {
                        return {
                            db_id: i.id,
                            label: i.label || '',
                            url: i.uazapi_url,
                            token: i.instance_token,
                            status: i.status || 'disconnected',
                            qrcode: null
                        };
                    });
                    safeStorage.setItem('whatsapp_instances', JSON.stringify(whatsappInstances));
                    renderInstances();
                }
            } catch(e) { debugLog('Erro ao carregar instancias do servidor:', e); }
        }

        function saveInstances() {
            safeStorage.setItem('whatsapp_instances', JSON.stringify(whatsappInstances));
            renderInstances();
        }

        function renderInstances() {
            const container = document.getElementById('instances-container');
            const countEl = document.getElementById('instance-count');
            const addBtn = document.getElementById('add-instance-btn');
            if (!container) return;
            if (countEl) countEl.textContent = whatsappInstances.length + '/' + MAX_INSTANCES;
            if (addBtn) addBtn.disabled = whatsappInstances.length >= MAX_INSTANCES;

            if (whatsappInstances.length === 0) {
                container.innerHTML = '<div class="text-center text-muted py-3"><i class="bi bi-phone fs-3 d-block mb-2"></i><small>Nenhuma instância configurada</small></div>';
                updateInstanceSelector();
                return;
            }

            let html = '';
            whatsappInstances.forEach(function(inst, index) {
                const sc = inst.status === 'connected' ? 'success' : 'danger';
                const st = inst.status === 'connected' ? 'Conectado' : 'Desconectado';
                const si = inst.status === 'connected' ? 'bi-check-circle-fill' : 'bi-x-circle-fill';
                html += '<div class="d-flex align-items-center justify-content-between p-2 mb-2 rounded" style="background:rgba(255,255,255,.03);border:1px solid rgba(255,255,255,.06);">';
                html += '<div class="d-flex align-items-center"><i class="bi bi-whatsapp text-success me-2"></i><div>';
                html += '<small class="fw-bold d-block">' + (inst.label || 'Instância ' + (index+1)) + '</small>';
                html += '<span class="badge bg-' + sc + '" style="font-size:0.65rem;"><i class="bi ' + si + ' me-1"></i>' + st + '</span>';
                html += '</div></div><div class="d-flex gap-1">';
                if (inst.status !== 'connected') {
                    html += '<button class="btn btn-outline-success btn-sm" onclick="connectInstance(' + index + ')" title="Conectar"><i class="bi bi-qr-code"></i></button>';
                }
                html += '<button class="btn btn-outline-info btn-sm" onclick="checkInstanceStatus(' + index + ')" title="Atualizar"><i class="bi bi-arrow-clockwise"></i></button>';
                html += '<button class="btn btn-outline-danger btn-sm" onclick="removeInstance(' + index + ')" title="Remover"><i class="bi bi-trash"></i></button>';
                html += '</div></div>';
                if (inst.qrcode) {
                    html += '<div class="text-center mb-2 p-2 rounded" style="background:white;" id="qr-' + index + '">';
                    html += '<img src="' + inst.qrcode + '" alt="QR Code" style="max-width:200px;width:100%;">';
                    html += '<small class="d-block text-dark mt-1">Escaneie com WhatsApp</small></div>';
                }
            });
            container.innerHTML = html;
            updateInstanceSelector();
        }

        function updateInstanceSelector() {
            const connected = whatsappInstances.filter(function(i) { return i.status === 'connected'; });
            let sel = document.getElementById('instance-selector');
            if (!sel && connected.length > 0) {
                const btn = document.getElementById('webhook-btn');
                if (btn) {
                    btn.parentElement.insertAdjacentHTML('beforebegin', '<select class="form-select form-select-sm mb-2" id="instance-selector"></select>');
                    sel = document.getElementById('instance-selector');
                }
            }
            if (sel) {
                let opts = '<option value="">Selecione a instância</option>';
                connected.forEach(function(inst) { opts += '<option value="' + inst.token + '">' + (inst.label || inst.token.substring(0,8)) + '</option>'; });
                sel.innerHTML = opts;
                if (connected.length === 1) sel.value = connected[0].token;
            }
        }

        function addInstance() {
