        async function createAndConnectInstance() {
            const label = document.getElementById('inst-label').value.trim() || 'WhatsApp ' + (whatsappInstances.length + 1);
            const btn = document.getElementById('create-inst-btn');
            const qrArea = document.getElementById('qr-area');

            if (btn) { btn.disabled = true; btn.innerHTML = '<span class="spinner-border spinner-border-sm me-2"></span>Criando...'; }
            if (qrArea) qrArea.classList.remove('d-none');

            try {
                const tenantId = currentTenant ? currentTenant.id : '';
                const resp = await fetch(getAuthWebhookBase() || '', {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({ action: 'create_instance', tenant_id: tenantId, label: label })
                });
                const data = await resp.json();

                if (data.success && data.instance) {
                    whatsappInstances.push({
                        db_id: data.instance.db_id || null,
                        label: label,
                        url: data.instance.url,
                        token: data.instance.token,
                        status: data.instance.status || 'disconnected',
                        qrcode: data.instance.qrcode || null
                    });
                    saveInstances();

                    if (data.instance.qrcode) {
                        var qs = document.getElementById('qr-spinner');
                        var qst = document.getElementById('qr-status');
                        var qd = document.getElementById('qr-display');
                        if (qs) qs.classList.add('d-none');
                        if (qst) qst.textContent = 'Escaneie o QR Code com seu WhatsApp:';
                        if (qd) qd.innerHTML = '<img src="' + data.instance.qrcode + '" style="max-width:250px;width:100%;border-radius:8px;">';
                        if (btn) btn.innerHTML = '<i class="bi bi-check me-1"></i>QR Gerado!';
                    } else {
                        const modal = bootstrap.Modal.getInstance(document.getElementById('addInstModal'));
                        if (modal) modal.hide();
                        showSuccessToast('Instancia criada! Clique em conectar para gerar QR.');
                    }
                } else {
                    throw new Error(data.error || 'Erro ao criar instancia');
                }
            } catch(e) {
                var qs2 = document.getElementById('qr-spinner');
                var qst2 = document.getElementById('qr-status');
                if (qs2) qs2.classList.add('d-none');
                if (qst2) qst2.innerHTML = '<span class="text-danger">' + e.message + '</span>';
                if (btn) { btn.disabled = false; btn.innerHTML = '<i class="bi bi-arrow-clockwise me-1"></i>Tentar Novamente'; }
            }
        }

        async function connectInstance(index) {
            const inst = whatsappInstances[index];
            if (!inst) return;
            showSuccessToast('Conectando...');
            try {
                await fetch(inst.url + '/instance/connect', {
                    method: 'POST', headers: { 'token': inst.token, 'Content-Type': 'application/json' }, body: '{}'
                });
                await new Promise(function(r) { setTimeout(r, 3000); });
                const resp = await fetch(inst.url + '/instance/status', { method: 'GET', headers: { 'token': inst.token } });
                if (!resp.ok) throw new Error('HTTP ' + resp.status);
                const data = await resp.json();
                let qr = data.qrcode || data.qr || data.qr_code || '';
                if (data.data) qr = data.data.qrcode || data.data.qr || qr;
                if (data.instance) qr = data.instance.qrcode || data.instance.qr || qr;
                if (qr && qr.length > 10) {
                    if (qr.indexOf('data:image') === -1 && qr.length > 100) qr = 'data:image/png;base64,' + qr;
                    inst.qrcode = qr; inst.status = 'disconnected';
                    showSuccessToast('QR Code gerado! Escaneie com WhatsApp.');
                } else {
                    let st = data.status || data.state || '';
                    if (data.data) st = data.data.status || data.data.state || st;
                    if (st === 'connected') { inst.status = 'connected'; inst.qrcode = null; showSuccessToast('Já conectado!'); }
                    else showErrorToast('QR indisponível. Tente novamente.');
                }
                saveInstances();
            } catch(e) { showErrorToast('Erro: ' + e.message); }
        }

        async function checkInstanceStatus(index) {
            const inst = whatsappInstances[index];
            if (!inst) return;
            try {
                const resp = await fetch(inst.url + '/instance/status', { method: 'GET', headers: { 'token': inst.token } });
                if (!resp.ok) throw new Error('HTTP ' + resp.status);
                const data = await resp.json();
                let st = data.status || data.state || '';
                if (data.data) st = data.data.status || data.data.state || st;
                if (data.instance) st = data.instance.status || data.instance.state || st;
                inst.status = (st === 'connected') ? 'connected' : 'disconnected';
                if (inst.status === 'connected') inst.qrcode = null;
                saveInstances();
                showSuccessToast('Status: ' + inst.status);
            } catch(e) { showErrorToast('Erro: ' + e.message); }
        }

        async function removeInstance(index) {
            if (!confirm('Remover esta instância?')) return;
            const inst = whatsappInstances[index];
            if (inst && inst.db_id && currentTenant && currentTenant.id) {
                try {
