        async function doRegister() {
            const empresa = document.getElementById('reg-empresa').value.trim();
            const email = document.getElementById('reg-email').value.trim();
            const password = document.getElementById('reg-password').value;
            const telefone = document.getElementById('reg-telefone').value.trim();

            if (!empresa || !email || !password) { showAuthError('Preencha empresa, email e senha'); return; }
            if (password.length < 6) { showAuthError('Senha deve ter no mínimo 6 caracteres'); return; }

            const btn = document.getElementById('register-btn');
            btn.disabled = true;
            btn.innerHTML = '<span class="spinner-border spinner-border-sm me-2"></span>Criando conta...';

            try {
                const resp = await fetch(getAuthWebhookBase() || '', {
