                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({ action: 'register', nome_empresa: empresa, email: email, password: password, telefone: telefone })
                });
                const data = await resp.json();
                if (data.success) {
                    currentTenant = data.tenant;
                    safeStorage.setItem('prospector_session', JSON.stringify(data.tenant));
                    enterApp();
                } else {
                    showAuthError(data.error || 'Erro ao criar conta');
                }
            } catch(e) {
                showAuthError('Erro de conexão: ' + e.message);
            } finally {
                btn.disabled = false;
                btn.innerHTML = '<i class="bi bi-person-plus me-2"></i>Criar Conta';
            }
        }

        function enterApp() {
            document.getElementById('login-screen').classList.add('d-none');
            document.getElementById('app-container').classList.remove('d-none');

            // Load tenant data into business profile
            if (currentTenant) {
                BUSINESS_PROFILE_CONFIG.nome_empresa = currentTenant.nome_empresa || '';
                BUSINESS_PROFILE_CONFIG.produtos_servicos = currentTenant.produtos_servicos || '';
                BUSINESS_PROFILE_CONFIG.icp = currentTenant.icp || '';
                BUSINESS_PROFILE_CONFIG.diferenciais = currentTenant.diferenciais || '';
                BUSINESS_PROFILE_CONFIG.tom_abordagem = currentTenant.tom_abordagem || 'consultivo';
                BUSINESS_PROFILE_CONFIG.proposta_valor = currentTenant.proposta_valor || '';
                BUSINESS_PROFILE_CONFIG.mensagem_padrao = currentTenant.mensagem_padrao || '';

                // Load API keys
                if (currentTenant.openai_api_key) {
                    safeStorage.setItem('openai_api_key', currentTenant.openai_api_key);
                }
                if (currentTenant.serpapi_key) {
                    SERPAPI_CONFIG.apiKey = currentTenant.serpapi_key;
                    safeStorage.setItem('serpapi_config', JSON.stringify({ apiKey: currentTenant.serpapi_key }));
                }
            }

            // Re-init
            updateSearchButtonState();
            updateWebhookButtons();
            if (miniMap) miniMap.invalidateSize();

            // Reload instances from server now that we have a tenant
            if (typeof loadInstances === 'function') loadInstances();
        }

        function doLogout() {
            currentTenant = null;
            safeStorage.removeItem('prospector_session');
            document.getElementById('app-container').classList.add('d-none');
            document.getElementById('login-screen').classList.remove('d-none');
            showLoginForm();
        }

        function checkSession() {
            const saved = safeStorage.getItem('prospector_session');
            if (saved) {
                try {
                    currentTenant = JSON.parse(saved);
                    enterApp();
                    return true;
                } catch(e) {}
            }
            return false;
        }

        // Save business profile to server
        async function syncProfileToServer() {
            if (!currentTenant || !currentTenant.id) return;
            try {
                await fetch(getAuthWebhookBase() || '', {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
